INSERT INTO FSI_DEMO_DB.INSURANCE.CLAIM_NOTES (NOTE_ID, CLAIM_ID, NOTE_DATE, AUTHOR_ID, AUTHOR_ROLE, NOTE_TYPE, CONTENT, SUMMARY, ACTION_REQUIRED, ACTION_DUE_DATE, EXTRACTED_ENTITIES, KEY_FINDINGS, CREATED_AT) VALUES
('CN00000000', 'CLM00000000', '2026-02-17 14:29:13.959', 'ADJ0000', 'CLAIMS_ADJUSTER', 'INITIAL_ASSESSMENT', 'Initial claim assessment completed. Policyholder reported collision at Main St and Oak Ave intersection. Police report obtained confirms other party at fault. Vehicle damage appears consistent with reported incident. Recommend proceeding with standard processing. Estimated repair cost: $2000. Coverage verified - comprehensive and collision in force.', 'Initial assessment complete; recommend standard processing', TRUE, '2026-02-20', 'Location: Main St/Oak Ave; Vehicle: 2022 Toyota Camry; Amount: $2000', 'Damage consistent with reported incident; coverage verified', '2026-02-17 14:29:13.959'),
('CN00000001', 'CLM00000001', '2026-02-17 12:49:13.959', 'SIU001', 'SPECIAL_INVESTIGATOR', 'INVESTIGATION_UPDATE', 'Spoke with claimant via phone. They provided additional details about the incident timeline. Witness contact information obtained. Claimant expressed concern about rental car coverage - confirmed policy includes 30 days rental reimbursement up to $50/day. Scheduled vehicle inspection for Thursday at preferred repair facility.', 'Claimant call - provided additional details, inspection scheduled', TRUE, '2026-02-21', 'Claimant Phone: (555) 123-4567; Repair Shop: AutoBody Plus; Rental: Enterprise', 'Claimant cooperative; rental coverage confirmed', '2026-02-17 14:29:13.959'),
('CN00000002', 'CLM00000002', '2026-02-17 11:09:13.959', 'SUP002', 'SUPERVISOR', 'DOCUMENT_REVIEW', 'Reviewed submitted documentation including photos of damage, repair estimates from two body shops, and medical records. Photos show impact damage consistent with side collision. Lower estimate selected from certified repair shop. Medical bills total $502 for ER visit and follow-up. All documentation appears complete.', 'Documentation review complete, all items received', FALSE, NULL, 'Body Shop: Certified Collision; Medical Provider: City Hospital ER', 'All documentation complete and verified', '2026-02-17 14:29:13.959'),
('CN00000003', 'CLM00000003', '2026-02-17 09:29:13.959', 'ADJ0003', 'CLAIMS_ADJUSTER', 'PHONE_CALL', 'Investigation update: Conducted recorded statement with insured. Timeline of events verified. No inconsistencies noted. Checked prior claim history - one minor claim 3 years ago, resolved without issue. No red flags identified. Recommend continuing standard claim processing without SIU referral.', 'Investigation update - no red flags, continue processing', FALSE, NULL, 'Prior Claim: CLM-2021-00123; Adjuster: John Smith', 'No fraud indicators; standard processing appropriate', '2026-02-17 14:29:13.959'),
('CN00000004', 'CLM00000004', '2026-02-17 07:49:13.959', 'SIU004', 'SPECIAL_INVESTIGATOR', 'SETTLEMENT_NEGOTIATION', 'Settlement offer presented to claimant: $3004 based on repair estimate plus diminished value consideration. Claimant initially requested higher amount citing emotional distress. Explained policy coverage limits and standard calculation methodology. Claimant accepted offer pending receipt of funds within 10 business days.', 'Settlement accepted at $3004', FALSE, NULL, 'Settlement: $3004; Payment Method: Direct Deposit', 'Settlement within guidelines; claimant satisfied', '2026-02-17 14:29:13.959'),
('CN00000005', 'CLM00000005', '2026-02-17 06:09:13.959', 'SUP005', 'SUPERVISOR', 'FINAL_REVIEW', 'Property inspection completed by field adjuster. Roof damage assessment: approximately 150 sq ft of shingles damaged by hail. Additional water damage in attic requiring remediation. Total estimate: $8005. Deductible: $1,500. Net payment to insured: $6505. Photos and measurements documented.', 'Property inspection complete, estimate $8005', TRUE, '2026-02-25', 'Property Address: 123 Oak Lane; Contractor: ABC Roofing', 'Enhanced review warranted based on claim characteristics', '2026-02-17 14:29:13.959'),
('CN00000006', 'CLM00000006', '2026-02-17 04:29:13.959', 'ADJ0006', 'CLAIMS_ADJUSTER', 'INITIAL_ASSESSMENT', 'SIU referral received for review. Claim exhibits some concerning indicators: policyholder increased coverage 60 days before loss, reported loss occurred with no witnesses, repair estimate seems high for described damage. Recommending enhanced investigation including EUO scheduling and social media review.', 'SIU referral - enhanced investigation recommended', TRUE, '2026-02-26', 'Location: Main St/Oak Ave; Vehicle: 2022 Toyota Camry; Amount: $2006', 'Damage consistent with reported incident; coverage verified', '2026-02-17 14:29:13.959'),
('CN00000007', 'CLM00000007', '2026-02-17 02:49:13.959', 'SIU007', 'SPECIAL_INVESTIGATOR', 'INVESTIGATION_UPDATE', 'Medical records review completed. Treatment appears reasonable and necessary for claimed injuries. Primary care physician confirms soft tissue injury consistent with motor vehicle accident. Physical therapy recommended for 6 weeks. No pre-existing conditions affecting claim. Medical reserve set at $2507.', 'Medical records reviewed - treatment reasonable', FALSE, NULL, 'Claimant Phone: (555) 123-4567; Repair Shop: AutoBody Plus; Rental: Enterprise', 'Claimant cooperative; rental coverage confirmed', '2026-02-17 14:29:13.959'),
('CN00000008', 'CLM00000008', '2026-02-17 01:09:13.959', 'SUP008', 'SUPERVISOR', 'DOCUMENT_REVIEW', 'Subrogation potential identified. Third party carrier (Nationwide) has accepted liability. Demand letter sent for $5008 representing our total payout plus loss adjustment expenses. Follow-up scheduled for 30 days. Recovery probability estimated at 85%.', 'Subrogation demand sent to third party carrier', FALSE, NULL, 'Body Shop: Certified Collision; Medical Provider: City Hospital ER', 'All documentation complete and verified', '2026-02-17 14:29:13.959'),
('CN00000009', 'CLM00000009', '2026-02-16 23:29:13.959', 'ADJ0009', 'CLAIMS_ADJUSTER', 'PHONE_CALL', 'Supervisor review completed. Claim handling meets all guidelines. Payment properly authorized and processed. File documentation complete and organized. No corrective actions needed. Claim ready for closure. Final payment: $4009. Total claim duration: 23 days.', 'Supervisor review passed - ready for closure', FALSE, NULL, 'Prior Claim: CLM-2021-00123; Adjuster: John Smith', 'No fraud indicators; standard processing appropriate', '2026-02-17 14:29:13.959'),
