-- FSI_DEMO_DB.INSURANCE.CLAIM_NOTES

CREATE OR REPLACE TABLE FSI_DEMO_DB.INSURANCE.CLAIM_NOTES (

    NOTE_ID VARCHAR(20) NOT NULL,
    CLAIM_ID VARCHAR(20),
    NOTE_DATE TIMESTAMP_NTZ(9),
    AUTHOR_ID VARCHAR(20),
    AUTHOR_ROLE VARCHAR(50),
    NOTE_TYPE VARCHAR(50),
    CONTENT VARCHAR(16777216),
    SUMMARY VARCHAR(500),
    ACTION_REQUIRED BOOLEAN DEFAULT FALSE,
    ACTION_DUE_DATE DATE,
    EXTRACTED_ENTITIES VARCHAR(16777216),
    KEY_FINDINGS VARCHAR(16777216),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (NOTE_ID)

);





